class Solution:
    def divisorSubstrings(self, num, k):
        s = str(num)
        windows = []
        for i in range(len(s) - k + 1):
            windows.append(int(s[i:i + k]))
        count = 0
        for w in windows:
            if w != 0 and num % w == 0:
                count += 1
        return count

