var divisorSubstrings = function(num, k) {
    const s = String(num);
    let count = 0;
    for (let i = 0; i + k <= s.length; i++) {
        const v = parseInt(s.slice(i, i + k), 10);
        if (v !== 0 && num % v === 0) count++;
    }
    return count;
};
